import { NextRequest, NextResponse } from 'next/server';

export async function POST(request: NextRequest) {
    const apiKey = process.env.DEEPGRAM_API_KEY;

    if (!apiKey) {
        return NextResponse.json(
            { error: 'DEEPGRAM_API_KEY not configured' },
            { status: 500 }
        );
    }

    try {
        const formData = await request.formData();
        const audioFile = formData.get('audio') as File;

        if (!audioFile) {
            return NextResponse.json(
                { error: 'No audio file provided' },
                { status: 400 }
            );
        }

        const audioBuffer = await audioFile.arrayBuffer();

        // Call Deepgram REST API for pre-recorded transcription
        const response = await fetch(
            'https://api.deepgram.com/v1/listen?model=nova-2&smart_format=true&language=en',
            {
                method: 'POST',
                headers: {
                    Authorization: `Token ${apiKey}`,
                    'Content-Type': audioFile.type || 'audio/webm',
                },
                body: audioBuffer,
            }
        );

        if (!response.ok) {
            const errorText = await response.text();
            console.error('Deepgram API error:', response.status, errorText);
            return NextResponse.json(
                { error: `Deepgram API error: ${response.status}` },
                { status: response.status }
            );
        }

        const data = await response.json();

        const transcript =
            data.results?.channels?.[0]?.alternatives?.[0]?.transcript || '';

        return NextResponse.json({
            transcript,
            confidence:
                data.results?.channels?.[0]?.alternatives?.[0]?.confidence || 0,
            metadata: {
                duration: data.metadata?.duration || 0,
                model: data.metadata?.model_info || 'nova-2',
            },
        });
    } catch (err) {
        console.error('Deepgram proxy error:', err);
        return NextResponse.json(
            { error: `Server error: ${err}` },
            { status: 500 }
        );
    }
}
